__CPROVER_assigns(__CPROVER_object_whole(bitlengths), __CPROVER_errno)
/* Every produced bit length is clamped/asserted non-negative. */
__CPROVER_ensures(__CPROVER_forall {
    size_t k; (k < n) ==> (bitlengths[k] >= 0)
